#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <string>
#include <vector>
#include "cJSON.h"
#include "lodepng.h"

static std::string readFile(const char* p){
    FILE* f=fopen(p,"rb");
    if(!f){fprintf(stderr,"cannot open %s\n",p);exit(1);}
    fseek(f,0,SEEK_END);long n=ftell(f);fseek(f,0,SEEK_SET);
    std::string s;s.resize(n);
    if(fread(&s[0],1,n,f)!=(size_t)n){fprintf(stderr,"read error\n");exit(1);}
    fclose(f);return s;
}

static std::vector<double> getArray(cJSON* root,const char* key){
    cJSON* a=cJSON_GetObjectItemCaseSensitive(root,key);
    if(!a){fprintf(stderr,"missing key %s\n",key);exit(1);}
    std::vector<double> out;
    // flatten nested arrays
    std::vector<cJSON*> stack; stack.push_back(a);
    // recursive flatten via lambda-like manual stack (depth-first, preserving order)
    // simpler: recursion
    struct F{ static void rec(cJSON* n,std::vector<double>& o){
        if(cJSON_IsArray(n)){
            cJSON* c=n->child;
            while(c){rec(c,o);c=c->next;}
        } else if(cJSON_IsNumber(n)){
            o.push_back(n->valuedouble);
        }
    }};
    F::rec(a,out);
    return out;
}

int main(int argc,char** argv){
    if(argc<3){fprintf(stderr,"usage: %s weights.json image.png\n",argv[0]);return 1;}
    std::string js=readFile(argv[1]);
    cJSON* root=cJSON_Parse(js.c_str());
    if(!root){fprintf(stderr,"json parse error\n");return 1;}

    std::vector<double> w0=getArray(root,"input_layer.weight");   // 16x784
    std::vector<double> b0=getArray(root,"input_layer.bias");     // 16
    std::vector<double> w1=getArray(root,"hidden_layer.weight");  // 16x16
    std::vector<double> b1=getArray(root,"hidden_layer.bias");    // 16
    std::vector<double> w2=getArray(root,"output_layer.weight");  // 10x16
    std::vector<double> b2=getArray(root,"output_layer.bias");    // 10

    int H0=(int)b0.size();   // 16
    int H1=(int)b1.size();   // 16
    int NC=(int)b2.size();   // 10
    int IN=784;

    // load image
    std::vector<unsigned char> img;
    unsigned iw,ih;
    unsigned err=lodepng::decode(img,iw,ih,argv[2],LCT_GREY,8);
    if(err){fprintf(stderr,"png error %u: %s\n",err,lodepng_error_text(err));return 1;}
    if((int)(iw*ih)!=IN){fprintf(stderr,"expected 28x28 image, got %ux%u\n",iw,ih);}

    std::vector<double> x(IN);
    for(int i=0;i<IN && i<(int)img.size();++i) x[i]=img[i]/255.0;

    // layer0
    std::vector<double> h0(H0);
    for(int i=0;i<H0;++i){double s=b0[i];const double* wr=&w0[(size_t)i*IN];for(int j=0;j<IN;++j)s+=wr[j]*x[j];h0[i]=s>0?s:0;}
    // layer1
    std::vector<double> h1(H1);
    for(int i=0;i<H1;++i){double s=b1[i];const double* wr=&w1[(size_t)i*H0];for(int j=0;j<H0;++j)s+=wr[j]*h0[j];h1[i]=s>0?s:0;}
    // output
    int best=0;double bestv=-1e300;
    for(int i=0;i<NC;++i){double s=b2[i];const double* wr=&w2[(size_t)i*H1];for(int j=0;j<H1;++j)s+=wr[j]*h1[j];if(s>bestv){bestv=s;best=i;}}

    printf("%d\n",best);
    cJSON_Delete(root);
    return 0;
}

